sqlMap.select:
	SELECT 
        GROUP_CONCAT(
            DISTINCT CONCAT(
                'MAX(IF(qrt.questionContent = ''', qrt.questionContent, ''', qrt.questionOptionsContent, '''')) AS `', CONCAT(
                    "questionResult", @rowNo := @rowNo + 1
                ), '`'
            )
        ) AS `columns`, COUNT(1) AS maxCount, GROUP_CONCAT(
            CONCAT("questionResult", @rowNo), "=", qrt.questionContent
        ) AS titles 
    FROM
        (SELECT DISTINCT 
            questionContent
        FROM
            $quesType$_tempQuesnaireResultLineTable

            questionType = #resultType# 

        ) qrt, 
        (SELECT 
            @rowNo := 0) b

    SELECT 
        GROUP_CONCAT(
            DISTINCT CONCAT(
                'MAX(IF(qrt.questionContent = ''', qrt.questionContent, ''', qrt.questionOptionsContent, '''')) AS `', CONCAT(
                    "questionResult", @rowNo := @rowNo + 1
                ), '`'
            )
        ) AS `columns`, COUNT(1) AS maxCount, GROUP_CONCAT(
            CONCAT("questionResult", @rowNo), "=", qrt.questionContent
        ) AS titles, CONCAT(
	        "CONCAT(", GROUP_CONCAT(
	            DISTINCT CONCAT(
	                "'questionResult", @rowNo, "=', ", 'MAX(IF(qrt.questionContent = ''', qrt.questionContent, ''', qrt.questionOptionsContent, ''''))'
	            ) SEPARATOR ",',',"
	        ), ")"
	    ) AS oneColumn
    FROM
        (SELECT DISTINCT 
            questionContent
        FROM
            $quesType$_tempQuesnaireResultLineTable

            questionType = #resultType# 

        ) qrt, 
        (SELECT 
            @rowNo := 0) b
